external_knowledge:
- 'wealthy clients' refers to customers classified as 'high net worth';
- 'solid credit standing' is indicated by a credit score of 700 or above;
- 'marketing efforts' refer to campaigns;
- 'successful' indicates a positive campaign outcome.

- 'gardeners of administration' refers to users with the role 'admin'.;
- 'seeds' metaphorically represent the campaigns, highlighting their foundational nature.;
- 'soil they were planted in' refers to the customer IDs, indicating the context where the campaigns are applied.;
- 'order of the breeze that whispers their names' symbolizes alphabetical order by the campaign names.

sql:
SELECT c.campaign_name, SINH(cu.age) AS transformed_age
FROM campaigns c
JOIN customers cu ON c.customer_id = cu.customer_id;

SELECT role, permission
FROM roles_permissions
WHERE role = 'admin' AND description LIKE '%view%';

SELECT customer_id, age, job, marital_status, education_level, default_status, gender, address, city, state, zip_code, email, registration_date, last_contact_date, preferred_contact_method, income_level, credit_score, is_vip, language_preferences, customer_segment
FROM customers
WHERE customer_id NOT IN (SELECT DISTINCT customer_id FROM campaigns);

SELECT campaign_id, RANK() OVER (ORDER BY budget DESC) AS rank
FROM campaigns
WHERE budget > 10000;

external_knowledge:
- 'Promotional campaign' refers to marketing activities aimed at attracting or retaining customers;
- 'Succeeded in' means the campaign resulted in a positive outcome, as defined by the 'success' outcome in the database;
- 'Personal and contact information' includes names, addresses, and contact methods, which in this context, are represented by age, job, marital status, and contact details;
- 'Financial status' includes income levels and credit scores, which provide insight into the customer's financial health;
- 'Customer classification' refers to whether they are VIPs and their customer segment.

